// EDTMRS - Main Dashboard Page
import React, { useState, useEffect } from 'react';
import { statsAPI } from '../utils/api';
import {
  Chart as ChartJS, CategoryScale, LinearScale,
  BarElement, LineElement, PointElement, Title, Tooltip, Legend, Filler
} from 'chart.js';
import { Bar, Line } from 'react-chartjs-2';

ChartJS.register(CategoryScale, LinearScale, BarElement, LineElement, PointElement, Title, Tooltip, Legend, Filler);

const CHART_OPTS = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: { legend: { display: false } },
  scales: {
    x: { grid: { color: '#1e2d4d' }, ticks: { color: '#64748b', font: { size: 11 } } },
    y: { grid: { color: '#1e2d4d' }, ticks: { color: '#64748b', font: { size: 11 } }, beginAtZero: true },
  },
};

function StatCard({ label, value, icon, color, sub }) {
  const colors = {
    blue:   { bg: 'bg-blue-500/10',    border: 'border-blue-500/30',   text: 'text-blue-400'   },
    green:  { bg: 'bg-emerald-500/10', border: 'border-emerald-500/30', text: 'text-emerald-400' },
    yellow: { bg: 'bg-yellow-500/10',  border: 'border-yellow-500/30', text: 'text-yellow-400'  },
    red:    { bg: 'bg-red-500/10',     border: 'border-red-500/30',    text: 'text-red-400'     },
    purple: { bg: 'bg-purple-500/10',  border: 'border-purple-500/30', text: 'text-purple-400'  },
  };
  const c = colors[color] || colors.blue;
  return (
    <div className={`rounded-xl border p-5 ${c.bg} ${c.border}`}>
      <div className="flex items-start justify-between mb-3">
        <span className="text-2xl">{icon}</span>
        <span className={`text-xs font-bold uppercase tracking-wider px-2 py-0.5 rounded-full ${c.bg} ${c.text} border ${c.border}`}>
          Live
        </span>
      </div>
      <div className={`text-3xl font-bold ${c.text} mb-1`}>{value ?? '—'}</div>
      <div className="text-gray-400 text-sm font-medium">{label}</div>
      {sub && <div className="text-gray-600 text-xs mt-1">{sub}</div>}
    </div>
  );
}

export default function DashboardPage({ liveEvents }) {
  const [stats, setStats]     = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchStats = async () => {
    try {
      const res = await statsAPI.get();
      setStats(res.data);
    } catch {}
    setLoading(false);
  };

  useEffect(() => {
    fetchStats();
    const interval = setInterval(fetchStats, 15000);
    return () => clearInterval(interval);
  }, []);

  // Refresh when live events arrive
  useEffect(() => {
    if (liveEvents?.length) fetchStats();
  }, [liveEvents]);

  const activityData = stats?.activity_7d || [];
  const chartLabels = activityData.map((d) => d.day?.slice(5) || '');
  const chartValues = activityData.map((d) => d.count);

  const barData = {
    labels: chartLabels,
    datasets: [{
      data: chartValues,
      backgroundColor: 'rgba(59,130,246,0.5)',
      borderColor: '#3b82f6',
      borderWidth: 2,
      borderRadius: 6,
    }],
  };

  const lineData = {
    labels: chartLabels,
    datasets: [{
      data: chartValues,
      borderColor: '#06b6d4',
      backgroundColor: 'rgba(6,182,212,0.1)',
      fill: true,
      tension: 0.4,
      pointBackgroundColor: '#06b6d4',
      pointRadius: 4,
    }],
  };

  return (
    <div className="space-y-6">
      {/* Page header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-white">Security Dashboard</h1>
          <p className="text-gray-500 text-sm mt-0.5">Real-time endpoint threat monitoring overview</p>
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-500/10 border border-emerald-500/30 rounded-full">
          <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse" />
          <span className="text-emerald-400 text-xs font-medium">Live Monitoring</span>
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center h-64">
          <div className="w-8 h-8 border-2 border-blue-500/30 border-t-blue-400 rounded-full animate-spin" />
        </div>
      ) : (
        <>
          {/* Stat cards */}
          <div className="grid grid-cols-2 xl:grid-cols-4 gap-4">
            <StatCard label="Total Endpoints"    value={stats?.total_endpoints}    icon="◈" color="blue"   sub={`${stats?.online_endpoints} online`} />
            <StatCard label="Devices Detected"   value={stats?.total_devices}      icon="⊞" color="purple" sub="All time" />
            <StatCard label="Suspicious Devices" value={stats?.suspicious_devices} icon="⚠" color="yellow" sub="High + Critical risk" />
            <StatCard label="Unread Alerts"      value={stats?.unacknowledged_alerts} icon="🔔" color="red" sub={`${stats?.total_alerts} total`} />
          </div>

          {/* Charts */}
          <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
            <div className="bg-[#0f1629] border border-[#1e2d4d] rounded-xl p-5">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-white font-semibold text-sm">Device Activity — Last 7 Days</h3>
                <span className="text-gray-500 text-xs">Bar Chart</span>
              </div>
              <div className="h-48">
                <Bar data={barData} options={CHART_OPTS} />
              </div>
            </div>
            <div className="bg-[#0f1629] border border-[#1e2d4d] rounded-xl p-5">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-white font-semibold text-sm">Activity Trend</h3>
                <span className="text-gray-500 text-xs">Line Chart</span>
              </div>
              <div className="h-48">
                <Line data={lineData} options={CHART_OPTS} />
              </div>
            </div>
          </div>

          {/* Live event feed */}
          <div className="bg-[#0f1629] border border-[#1e2d4d] rounded-xl p-5">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-white font-semibold text-sm">Live Event Feed</h3>
              <span className="text-gray-500 text-xs">{liveEvents?.length || 0} events this session</span>
            </div>
            {!liveEvents?.length ? (
              <div className="text-center py-10 text-gray-600">
                <div className="text-3xl mb-2">⊡</div>
                <div className="text-sm">No live events yet. Insert a USB device on any endpoint.</div>
              </div>
            ) : (
              <div className="space-y-2 max-h-64 overflow-y-auto">
                {[...liveEvents].reverse().slice(0, 20).map((ev, i) => (
                  <div key={i} className="flex items-center gap-3 px-3 py-2.5 bg-[#141d35] rounded-lg text-sm">
                    <span className={`w-2 h-2 rounded-full flex-shrink-0 ${
                      ev.risk_level === 'critical' ? 'bg-red-400' :
                      ev.risk_level === 'high'     ? 'bg-orange-400' :
                      ev.risk_level === 'medium'   ? 'bg-yellow-400' : 'bg-emerald-400'
                    }`} />
                    <span className="text-gray-300 font-medium truncate flex-1">{ev.device_name}</span>
                    <span className="text-gray-500 text-xs">{ev.hostname}</span>
                    <span className="text-gray-600 text-xs">{ev.timestamp?.slice(11, 19) || 'now'}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}
